(function(){if(window.btdt&&window.btdt._initialized)return;const VERSION='0.0.5';const script=document.currentScript;if(!script)return;const detectedBase=script.src.split('/').slice(0,-2).join('/')+'/';const basePath=(script.getAttribute('data-base-path')||detectedBase).replace(/\/?$/,'/');const autoInit=script.getAttribute('data-auto-init')!=='false';const initialPreset=script.getAttribute('data-preset')||null;const defaultMinified=script.getAttribute('data-minified')==='true';const darkValue=script.getAttribute('data-dark-value')||null;const darkCookieName=script.getAttribute('data-dark-cookie')||null;const cookieExpire=parseInt(script.getAttribute('data-cookie-expire')||'0',10);const useSystemDark=script.getAttribute('data-dark-system')==='true';const DARK_VALUES=new Set(['1','true','yes','dark','on']);const LIGHT_VALUES=new Set(['0','false','no','light','off']);function classifyValue(value){if(value==null)return null;const n=String(value).trim().toLowerCase();if(DARK_VALUES.has(n))return'dark';if(LIGHT_VALUES.has(n))return'light';return null;}
function getCookie(name){const match=document.cookie.match(new RegExp('(?:^|; )'+name.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')+'=([^;]*)'));return match?decodeURIComponent(match[1]):null;}
function resolveTargetMode(){if(darkValue){const r=classifyValue(darkValue);if(r)return r;}
if(darkCookieName){const r=classifyValue(getCookie(darkCookieName));if(r)return r;}
if(useSystemDark&&window.matchMedia){return window.matchMedia('(prefers-color-scheme: dark)').matches?'dark':'light';}
return'light';}
const targetMode=resolveTargetMode();const html=document.documentElement;html.setAttribute('data-bs-theme',targetMode);if(targetMode==='dark'){html.setAttribute('data-mode','dark');}else{html.removeAttribute('data-mode');}
function findLinkByFilename(filename){const links=document.head.querySelectorAll('link[rel="stylesheet"]');for(let i=0;i<links.length;i++){const url=new URL(links[i].href);if(url.pathname.includes(filename))return links[i];}
return null;}
function findPresetLink(){return document.getElementById('theme-preset')||findLinkByFilename('themes/preset/')||null;}
function resolvePresetHref(name,options){if(!name)return null;if(name.endsWith('.css')||name.includes('/'))return name;const min=(options&&options.minified!=null)?options.minified:defaultMinified;return`${basePath}themes/preset/${name}${min ? '.min' : ''}.css`;}
function ensurePresetLink(){const existing=findPresetLink();if(existing){existing.id='theme-preset';return existing;}
const link=document.createElement('link');link.id='theme-preset';link.rel='stylesheet';document.head.appendChild(link);return link;}
function ensureModeLink(){let link=document.getElementById('theme-preset-dark');if(!link){link=document.createElement('link');link.id='theme-preset-dark';link.rel='stylesheet';link.href=`${basePath}themes/modes/dark.min.css?v=${VERSION}`;document.head.appendChild(link);}
link.media=targetMode==='dark'?'all':'not all';return link;}
function syncModeUI(mode){const isDark=mode==='dark';if(darkCookieName&&!darkValue){let cookieStr=`${darkCookieName}=${mode}; path=/`;if(cookieExpire>0){const date=new Date();date.setDate(date.getDate()+cookieExpire);cookieStr+=`; expires=${date.toUTCString()}`;}
document.cookie=cookieStr;}
document.querySelectorAll('.dark-mode-enabled').forEach((el)=>{el.classList.toggle('display-none',!isDark);});document.querySelectorAll('.dark-mode-disabled').forEach((el)=>{el.classList.toggle('display-none',isDark);});}
function applyMode(mode){const normalized=mode==='dark'?'dark':'light';const modeLink=ensureModeLink();html.setAttribute('data-bs-theme',normalized);if(normalized==='dark'){html.setAttribute('data-mode','dark');modeLink.media='all';}else{html.removeAttribute('data-mode');modeLink.media='not all';}
syncModeUI(normalized);html.dispatchEvent(new CustomEvent('btdt:modechange',{bubbles:true,detail:{mode:normalized}}));return normalized;}
window.btdt={_initialized:true,_mode:targetMode,load:function(name,options){const href=resolvePresetHref(name,options);if(!href)return this;const link=ensurePresetLink();if(link.href!==href)link.href=href;return this;},setMode:function(mode){this._mode=applyMode(mode);return this;},toggleMode:function(){return this.setMode(this._mode==='dark'?'light':'dark');},getMode:function(){return this._mode;}};if(autoInit){const existingPreset=findPresetLink();if(existingPreset){existingPreset.id='theme-preset';}else if(initialPreset){window.btdt.load(initialPreset);}
ensureModeLink();if(useSystemDark&&!darkValue&&!darkCookieName&&window.matchMedia){window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change',function(e){window.btdt.setMode(e.matches?'dark':'light');});}
document.addEventListener('DOMContentLoaded',function(){syncModeUI(targetMode);document.addEventListener('click',function(ev){const btn=ev.target.closest('.theme-light-dark-toggle');if(!btn)return;ev.preventDefault();window.btdt.toggleMode();});});}})();